{
  "day": "1",
  "heading": "Drive from Rishikesh to Karchi",
  "sub_heading": "Drive Distance: 254 km | Drive Duration: 10-11 hours | Pick up point for Indiahikes trekkers: Live Free Hostel, Rishikesh | Pick up Time: 5.30 am | Location of Indiahikes basecamp: Karchi",
  "details": "Transport will be arranged at 5.30 AM. The cost of the cab will be Rs 1400 (additional 5% GST) per trekker (one-way) one way.  You will reach the base camp, Karchi by 5.00 PM.  Please pre-book your transport through the dashboard before your trek."
}

{
  "day": "2",
  "heading": "Drive from Karchi to Auli. Trek from Auli to Tali",
  "sub_heading": "Trek Distance: 8.1 km | Trek Duration: 8-9 hours | Altitude Gain: 7,785 ft to 11,053 ft",
  "details": ""
}

{
  "day": "3",
  "heading": "Trek from Tali to Khullara",
  "sub_heading": "Trek Distance: 2.65 km | Trek Duration: 3 hours | Altitude Gain and Loss: 11,053 ft to 11,014 ft",
  "details": ""
}

{
  "day": "4",
  "heading": "Acclimatization Day at Khullara. Trek to Kuari Top and back to Khullara",
  "sub_heading": "Trek Distance: 7 km | Trek Duration: 4-5 hours | Altitude Gain and Loss: 11,010 ft to 12,600 ft, and back to 11,010 ft",
  "details": ""
}

{
  "day": "5",
  "heading": "Trek from Khullara to Pangarchulla Summit, and back to Khullara",
  "sub_heading": "Trek Distance: 12 km | Trek Duration: 10-12 hours | Altitude Gain and Loss: 11,010 ft to 15,069 ft, and back to 11,010 ft",
  "details": ""
}

{
  "day": "6",
  "heading": "Trek from Khullara to Karchi",
  "sub_heading": "Trek Distance: 5.25 km | Trek Duration: 3-4 hours | Altitude Loss: 11,010 ft to 7,785 ft",
  "details": ""
}

{
  "day": "7",
  "heading": "Drive back from Karchi to Rishikesh",
  "sub_heading": "Drive Distance: 260 km | Trek Duration: 10-11 hours | Drop off point for Indiahikes trekkers: Live Free Hostel, Rishikesh",
  "details": "The transport cost has to be borne by trekkers. It costs Rs 1500 (an additional 5% GST) per trekker to Rishikesh. (This includes the extra charges from Auli to Karchi).  Please pre-book your transport through the dashboard before your trek.\nPlease note: The distance between campsites may vary by 100 meters depending the weather conditions and the route you take. The altitude may also vary by 100 feet for similar reasons."
}
